@startuml
!theme plain
skinparam backgroundColor #FFFFFF
skinparam rectangle {
  BackgroundColor #F5F5F5
  BorderColor #000000
  BorderThickness 1
  FontColor #000000
}
rectangle "Class" as Class {
  rectangle "Attribute" as Attribute
  rectangle "Method" as Method
}
Class {
  [
    + attribute: String
    - attribute: Integer
    # method: void
    # method: String
  ]
}
@enduml
